                                className="rounded border border-gray-300 p-2 text-sm outline-none focus:border-red-500"
                                value={newEvent.date}
                                onChange={(e) => setNewEvent({ ...newEvent, date: e.target.value })}
                            />
                            <input
                                type="text"
                                placeholder="Venue"
                                className="rounded border border-gray-300 p-2 text-sm outline-none focus:border-red-500"
                                value={newEvent.venue}
