                                className="rounded border border-gray-300 p-2 text-sm outline-none focus:border-red-500"
                                value={newEvent.registrationLink}
                                onChange={(e) => setNewEvent({ ...newEvent, registrationLink: e.target.value })}
                            />
                            <textarea
